def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        residual = capacity - item
        for depth in range(1, 5):
            if residual <= 0:
                score += 15 / depth
            else:
                score += (1 / residual) * depth
            residual *= 0.6
        multiplier = 1.0
        if capacity > 3 * item:
            multiplier = 0.85
        elif capacity > 2 * item:
            multiplier = 0.95
        elif capacity > item:
            multiplier = 1.1
        else:
            multiplier = 1.3
        score *= multiplier
        penalty = 0
        for check in range(1, int(item)+1):
            if (capacity - check) % 2 == 0:
                penalty += 0.2 * check
            else:
                penalty -= 0.1 * check
        score += penalty
        if score < 0:
            priorities[i] = 0
        elif score > 150:
            priorities[i] = 150
        else:
            priorities[i] = score
    return priorities
